import CryptoJS from 'crypto-js';
import { ENCRYPTION_KEY, ENCRYPTION_IV, STORAGE_PREFIX } from '../config/encryptionConfig';

class EncryptionService {
  constructor() {
    this.key = CryptoJS.enc.Hex.parse(ENCRYPTION_KEY);
    this.iv = CryptoJS.enc.Utf8.parse(ENCRYPTION_IV);
  }

  encrypt(data) {
    try {
      if (data === null || data === undefined) {
        throw new Error('Cannot encrypt null or undefined data');
      }

      const stringData = typeof data === 'string' ? data : JSON.stringify(data);

      const encrypted = CryptoJS.AES.encrypt(stringData, this.key, {
        iv: this.iv,
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7,
      });

      return encrypted.toString();
    } catch (error) {
      console.error('Encryption error:', error.message);
      throw new Error(`Encryption failed: ${error.message}`);
    }
  }

  decrypt(encryptedData) {
    try {
      if (!encryptedData) {
        throw new Error('Cannot decrypt empty data');
      }

      const decrypted = CryptoJS.AES.decrypt(encryptedData, this.key, {
        iv: this.iv,
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7,
      });

      const decryptedString = decrypted.toString(CryptoJS.enc.Utf8);

      if (!decryptedString) {
        throw new Error('Decryption resulted in empty string - possible key mismatch');
      }

      return decryptedString;
    } catch (error) {
      console.error('Decryption error:', error.message);
      throw new Error(`Decryption failed: ${error.message}`);
    }
  }

  decryptToObject(encryptedData) {
    const decryptedString = this.decrypt(encryptedData);
    try {
      return JSON.parse(decryptedString);
    } catch {
      return decryptedString;
    }
  }

  generateHMAC(data) {
    const stringData = typeof data === 'string' ? data : JSON.stringify(data);
    return CryptoJS.HmacSHA256(stringData, this.key).toString();
  }

  hashData(data) {
    const stringData = typeof data === 'string' ? data : JSON.stringify(data);
    return CryptoJS.SHA256(stringData).toString();
  }
}

