import AsyncStorage from '@react-native-async-storage/async-storage';
import encryptionService from './encryption';
import { STORAGE_PREFIX } from '../config/encryptionConfig';

const STORAGE_KEYS = {
  USER_PROFILE: `${STORAGE_PREFIX}user_profile`,
  PAYMENT_INFO: `${STORAGE_PREFIX}payment_info`,
  AUTH_TOKEN: `${STORAGE_PREFIX}auth_token`,
  REFRESH_TOKEN: `${STORAGE_PREFIX}refresh_token`,
  USER_PREFERENCES: `${STORAGE_PREFIX}user_preferences`,
  SESSION_DATA: `${STORAGE_PREFIX}session_data`,
};

class SecureStorage {
  async setItem(key, value) {
    try {
      const encrypted = encryptionService.encrypt(value);
      const hmac = encryptionService.generateHMAC(encrypted);

      const storagePayload = JSON.stringify({
        data: encrypted,
        hmac: hmac,
        timestamp: Date.now(),
      });

      await AsyncStorage.setItem(key, storagePayload);
      return true;
    } catch (error) {
      console.error(`SecureStorage setItem error for key ${key}:`, error.message);
      throw error;
    }
  }

  async getItem(key) {
    try {
      const raw = await AsyncStorage.getItem(key);

      if (!raw) {
        return null;
      }

      const payload = JSON.parse(raw);

      const computedHmac = encryptionService.generateHMAC(payload.data);
      if (computedHmac !== payload.hmac) {
        console.error('HMAC verification failed - data may have been tampered with');
        await this.removeItem(key);
        throw new Error('Data integrity check failed');
      }

      return encryptionService.decryptToObject(payload.data);
    } catch (error) {
      if (error.message === 'Data integrity check failed') {
        throw error;
      }
      console.error(`SecureStorage getItem error for key ${key}:`, error.message);
      throw error;
    }
  }

  async removeItem(key) {
    try {
      await AsyncStorage.removeItem(key);
      return true;
    } catch (error) {
      console.error(`SecureStorage removeItem error for key ${key}:`, error.message);
      throw error;
    }
  }

  async clearAll() {
    try {
      const allKeys = await AsyncStorage.getAllKeys();
      const secureKeys = allKeys.filter((key) => key.startsWith(STORAGE_PREFIX));
      await AsyncStorage.multiRemove(secureKeys);
      return true;
    } catch (error) {
      console.error('SecureStorage clearAll error:', error.message);
      throw error;
    }
  }

  async getAllSecureKeys() {
    try {
      const allKeys = await AsyncStorage.getAllKeys();
      return allKeys.filter((key) => key.startsWith(STORAGE_PREFIX));
    } catch (error) {
      console.error('SecureStorage getAllSecureKeys error:', error.message);
      throw error;
    }
  }

  // --- User Profile Methods ---

  async saveUserProfile(profile) {
    if (!profile || typeof profile !== 'object') {
      throw new Error('Invalid profile data');
    }

    const sanitizedProfile = {
      id: profile.id,
      email: profile.email,
      firstName: profile.firstName,
      lastName: profile.lastName,
      phone: profile.phone,
      avatar: profile.avatar,
      dateOfBirth: profile.dateOfBirth,
      address: profile.address,
      updatedAt: Date.now(),
    };

    return this.setItem(STORAGE_KEYS.USER_PROFILE, sanitizedProfile);
  }

  async getUserProfile() {
    return this.getItem(STORAGE_KEYS.USER_PROFILE);
  }

  async removeUserProfile() {
    return this.removeItem(STORAGE_KEYS.USER_PROFILE);
  }

  // --- Payment Information Methods ---

  async savePaymentInfo(paymentData) {
    if (!paymentData || typeof paymentData !== 'object') {
      throw new Error('Invalid payment data');
    }

    const sanitizedPayment = {
      cards: (paymentData.cards || []).map((card) => ({
        id: card.id,
        lastFourDigits: card.cardNumber ? card.cardNumber.slice(-4) : card.lastFourDigits,
        encryptedCardNumber: card.cardNumber
          ? encryptionService.hashData(card.cardNumber)
          : card.encryptedCardNumber,
        cardholderName: card.cardholderName,
        expiryMonth: card.expiryMonth,
        expiryYear: card.expiryYear,
        cardType: card.cardType,
        isDefault: card.isDefault || false,
        billingAddress: card.billingAddress,
      })),
      preferredPaymentMethod: paymentData.preferredPaymentMethod,
      updatedAt: Date.now(),
    };

    return this.setItem(STORAGE_KEYS.PAYMENT_INFO, sanitizedPayment);
  }

  async getPaymentInfo() {
    return this.getItem(STORAGE_KEYS.PAYMENT_INFO);
  }

  async removePaymentInfo() {
    return this.removeItem(STORAGE_KEYS.PAYMENT_INFO);
  }

  async addPaymentCard(card) {
    const existingPaymentInfo = (await this.getPaymentInfo()) || { cards: [] };

    const newCard = {
      id: `card_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      ...card,
    };

    existingPaymentInfo.cards.push(newCard);

    if (existingPaymentInfo.cards.length === 1) {
      existingPaymentInfo.cards[0].isDefault = true;
    }

    return this.savePaymentInfo(existingPaymentInfo);
  }

  async removePaymentCard(cardId) {
    const paymentInfo = await this.getPaymentInfo();

    if (!paymentInfo || !paymentInfo.cards) {
      throw new Error('No payment information found');
    }

    paymentInfo.cards = paymentInfo.cards.filter((card) => card.id !== cardId);
    return this.savePaymentInfo(paymentInfo);
  }

  // --- Auth Token Methods ---

  async saveAuthTokens(tokens) {
    if (!tokens) {
      throw new Error('Invalid token data');
    }

    const tokenData = {
      accessToken: tokens.accessToken,
      tokenType: tokens.tokenType || 'Bearer',
      expiresAt: tokens.expiresIn
        ? Date.now() + tokens.expiresIn * 1000
        : tokens.expiresAt,
      scope: tokens.scope,
      storedAt: Date.now(),
    };

    await this.setItem(STORAGE_KEYS.AUTH_TOKEN, tokenData);

    if (tokens.refreshToken) {
      await this.setItem(STORAGE_KEYS.REFRESH_TOKEN, {
        refreshToken: tokens.refreshToken,
        storedAt: Date.now(),
      });
    }

    return true;
  }

  async getAuthToken() {
    try {
      const tokenData = await this.getItem(STORAGE_KEYS.AUTH_TOKEN);

      if (!tokenData) {
        return null;
      }

      if (tokenData.expiresAt && Date.now() > tokenData.expiresAt) {
        console.warn('Auth token has expired');
        return {
          ...tokenData,
          isExpired: true,
        };
      }

      return {
        ...tokenData,
        isExpired: false,
      };
    } catch (error) {
      console.error('Error retrieving auth token:', error.message);
      return null;
    }
  }

  async getRefreshToken() {
    try {
      const tokenData = await this.getItem(STORAGE_KEYS.REFRESH_TOKEN);
      return tokenData ? tokenData.refreshToken : null;
    } catch (error) {
      console.error('Error retrieving refresh token:', error.message);
      return null;
    }
  }

  async isAuthenticated() {
    const token = await this.getAuthToken();
    return token !== null && !token.isExpired;
  }

  async removeAuthTokens() {
    await this.removeItem(STORAGE_KEYS.AUTH_TOKEN);
    await this.removeItem(STORAGE_KEYS.REFRESH_TOKEN);
    return true;
  }

  // --- Session Data Methods ---

  async saveSessionData(sessionData) {
    return this.setItem(STORAGE_KEYS.SESSION_DATA, {
      ...sessionData,
      updatedAt: Date.now(),
    });
  }

  async getSessionData() {
    return this.getItem(STORAGE_KEYS.SESSION_DATA);
  }

  // --- User Preferences (encrypted) ---

  async saveUserPreferences(preferences) {
    return this.setItem(STORAGE_KEYS.USER_PREFERENCES, {
      ...preferences,
      updatedAt: Date.now(),
    });
  }

  async getUserPreferences() {
    return this.getItem(STORAGE_KEYS.USER_PREFERENCES);
  }

  // --- Full Logout / Data Wipe ---

  async performSecureLogout() {
    try {
      await this.removeAuthTokens();
      await this.removeItem(STORAGE_KEYS.SESSION_DATA);
      console.log('Secure logout completed');
      return true;
    } catch (error) {
      console.error('Secure logout error:', error.message);
      await this.clearAll();
      return true;
    }
  }

  async performFullDataWipe() {
    try {
      await this.clearAll();
      console.log('Full data wipe completed');
      return true;
    } catch (error) {
      console.error('Full data wipe error:', error.message);
      throw error;
    }
  }
}

