// hooks/useSecureStorage.js
import { useState, useEffect, useCallback } from 'react';
import secureStorage from '../utils/secureStorage';

export function useUserProfile() {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const loadProfile = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await secureStorage.getUserProfile();
      setProfile(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  const saveProfile = useCallback(async (profileData) => {
    try {
      setError(null);
      await secureStorage.saveUserProfile(profileData);
      setProfile(profileData);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    }
  }, []);

  const removeProfile = useCallback(async () => {
    try {
      setError(null);
      await secureStorage.removeUserProfile();
      setProfile(null);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    }
  }, []);

  useEffect(() => {
    loadProfile();
  }, [loadProfile]);

  return { profile, loading, error, saveProfile, removeProfile, refreshProfile: loadProfile };
}

export function usePaymentInfo() {
  const [paymentInfo, setPaymentInfo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const loadPaymentInfo = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await secureStorage.getPaymentInfo();
      setPaymentInfo(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  const savePaymentInfo = useCallback(async (data) => {
    try {
      setError(null);
      await secureStorage.savePaymentInfo(data);
      setPaymentInfo(data);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    }
  }, []);

  const addCard = useCallback(async (card) => {
    try {
      setError(null);
      await secureStorage.addPaymentCard(card);
      await loadPaymentInfo();
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    }
  }, [loadPaymentInfo]);

  const removeCard = useCallback(async (cardId) => {
    try {
      setError(null);
      await secureStorage.removePaymentCard(cardId);
      await loadPaymentInfo();
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    }
  }, [loadPaymentInfo]);

  useEffect(() => {
    loadPaymentInfo();
  }, [loadPaymentInfo]);

  return {
    paymentInfo,
    loading,
    error,
    savePaymentInfo,
    addCard,
    removeCard,
    refreshPaymentInfo: loadPaymentInfo,
  };
}

export function useAuth() {
  const [authToken, setAuthToken] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const checkAuth = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const token = await secureStorage.getAuthToken();
      const authenticated = await secureStorage.isAuthenticated();
      setAuthToken(token);
      setIsAuthenticated(authenticated);
    } catch (err) {
      setError(err.message);
      setIsAuthenticated(false);
    } finally {
      setLoading(false);
    }
  }, []);

  const login = useCallback(async (tokens) => {
    try {
      setError(null);
      await secureStorage.saveAuthTokens(tokens);
      const token = await secureStorage.getAuthToken();
      setAuthToken(token);
      setIsAuthenticated(true);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    }
  }, []);

  const logout = useCallback(async () => {
    try {
      setError(null);
      await secureStorage.performSecureLogout();
      setAuthToken(null);
      setIsAuthenticated(false);
      return true;
    } catch (err) {
      setError(err.message);
      return false;
    }
  }, []);

  const getRefreshToken = useCallback(async () => {
    try {
      return await secureStorage.getRefreshToken();
    } catch (err) {
      setError(err.message);
      return null;
    }
  }, []);

  useEffect(() => {
    checkAuth();
  }, [checkAuth]);

  return {
    authToken,
    isAuthenticated,
    loading,
    error,
    login,
    logout,
    getRefreshToken,
    refreshAuth: checkAuth,
  };
}

