function EncryptionDemo() {
  const [demoResult, setDemoResult] = React.useState('');

  const runEncryptionDemo = () => {
    const testData = { message: 'Hello, Secure World!', timestamp: Date.now() };
    const encrypted = encryptionService.encrypt(testData);
    const decrypted = encryptionService.decryptToObject(encrypted);
    const hash = encryptionService.hashData(testData);
    const hmac = encryptionService.generateHMAC(testData);

    setDemoResult(
      `Original: ${JSON.stringify(testData)}\n\n` +
      `Encrypted: ${encrypted.substring(0, 50)}...\n\n` +
      `Decrypted: ${JSON.stringify(decrypted)}\n\n` +
      `SHA256 Hash: ${hash.substring(0, 40)}...\n\n` +
      `HMAC: ${hmac.substring(0, 40)}...`
    );
  };

  return (
    <View>
      <SectionHeader title="Encryption Demo" />
      <ActionButton title="Run Encryption Test" onPress={runEncryptionDemo} color="#5856D6" />
      {demoResult ? (
        <View style={styles.resultBox}>
          <Text style={styles.resultText}>{demoResult}</Text>
        </View>
      ) : null}
    </View>
  );
}

